import React, { useState, useEffect, useRef } from "react";
import { motion } from "framer-motion";

export default function MapleLuxeSite() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [showBackToTop, setShowBackToTop] = useState(false);
  const [formStatus, setFormStatus] = useState(null);
  const [uploadedFiles, setUploadedFiles] = useState([]);

  useEffect(() => {
    const handleScroll = () => setShowBackToTop(window.scrollY > 400);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const scrollToTop = () => window.scrollTo({ top: 0, behavior: "smooth" });

  const handleSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData(e.target);
    try {
      await fetch("https://formsubmit.co/ajax/mapleluxebookings@gmail.com", {
        method: "POST",
        body: formData,
      });
      setFormStatus("success");
      e.target.reset();
      setUploadedFiles([]);
      setTimeout(() => setFormStatus(null), 5000);
    } catch {
      setFormStatus("error");
      setTimeout(() => setFormStatus(null), 5000);
    }
  };

  const handleFileChange = (e) => setUploadedFiles(Array.from(e.target.files));

  const fadeUp = { hidden: { opacity: 0, y: 24 }, visible: { opacity: 1, y: 0 } };
  const stagger = { visible: { transition: { staggerChildren: 0.08 } } };

  const navItems = ["Services", "Why Us", "Projects", "Reviews", "Contact"];

  const services = [
    { title: "Fencing & Decking", desc: "Custom wood & composite builds designed for Calgary's seasons.", icon: <FenceIcon /> },
    { title: "Landscaping", desc: "Design, hardscapes, lighting and year-round care.", icon: <LeafIcon /> },
    { title: "Property Management", desc: "Tenant relations, inspections, financials, compliance.", icon: <KeysIcon /> },
    { title: "Custom Design Build", desc: "Tailored outdoor solutions designed for your lifestyle.", icon: <MegaphoneIcon /> },
    { title: "Maintenance & Repairs", desc: "Preventative programs and 24/7 response.", icon: <WrenchIcon /> },
    { title: "Cleaning & Turnover", desc: "Move-in/out, common areas and deep clean crews.", icon: <SparkleIcon /> },
  ];

  const marqueeItems = [
    "Fencing & Decking", "Property Management", "Landscaping", "Custom Design Build",
    "Maintenance & Repairs", "Cleaning & Turnover", "Calgary Licensed", "Warranty Protected",
    "24/7 Emergency", "Weekly Reporting",
  ];

  return (
    <div className="min-h-screen bg-[#060A12] text-[#E2E8F0] overflow-x-hidden">

      {/* Ambient background glows */}
      <div className="fixed inset-0 pointer-events-none z-0">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[900px] h-[600px] bg-[radial-gradient(ellipse_at_top,rgba(59,130,246,0.18)_0%,transparent_70%)]" />
        <div className="absolute top-1/3 right-0 w-[500px] h-[500px] bg-[radial-gradient(circle,rgba(139,92,246,0.1)_0%,transparent_70%)]" />
        <div className="absolute bottom-0 left-0 w-[400px] h-[400px] bg-[radial-gradient(circle,rgba(59,130,246,0.08)_0%,transparent_70%)]" />
      </div>

      {/* Back to Top */}
      {showBackToTop && (
        <button
          onClick={scrollToTop}
          className="fixed bottom-24 right-6 z-50 bg-[#3B82F6] text-white p-3 rounded-full shadow-lg shadow-blue-500/20 hover:scale-110 transition-transform"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" />
          </svg>
        </button>
      )}

      {/* Floating CTA */}
      <div className="fixed bottom-6 right-6 z-50">
        <a href="#contact" className="inline-flex items-center gap-2 px-5 py-3 text-sm font-semibold text-white bg-gradient-to-r from-[#3B82F6] to-[#8B5CF6] rounded-full shadow-2xl shadow-blue-500/30 hover:scale-105 transition-transform">
          <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z" />
          </svg>
          Free Quote
        </a>
      </div>

      {/* ─── NAV ─── */}
      <header className="sticky top-0 z-40 border-b border-white/[0.06] bg-[#060A12]/80 backdrop-blur-2xl">
        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
          <div className="flex h-16 items-center justify-between gap-4">

            {/* Logo */}
            <div className="flex items-center gap-3">
              <div className="h-9 w-9 rounded-xl bg-gradient-to-br from-[#3B82F6] to-[#8B5CF6] grid place-items-center shadow-lg shadow-blue-500/20">
                <span className="text-white font-black text-base">M</span>
              </div>
              <div className="leading-tight">
                <div className="text-base font-extrabold tracking-tight text-white">MapleLuxe</div>
                <div className="text-[10px] uppercase tracking-[0.18em] text-white/40">Premium Property Ops</div>
              </div>
            </div>

            {/* Desktop nav */}
            <nav className="hidden lg:flex items-center gap-1 rounded-2xl border border-white/[0.08] bg-white/[0.03] p-1 text-sm backdrop-blur">
              {navItems.map((item) => (
                <a
                  key={item}
                  href={`#${item.toLowerCase() === "reviews" ? "testimonials" : item.toLowerCase()}`}
                  className="rounded-xl px-4 py-2 text-white/70 transition hover:bg-white/[0.06] hover:text-white"
                >
                  {item}
                </a>
              ))}
            </nav>

            <div className="flex items-center gap-3">
              <div className="hidden md:flex items-center gap-2 rounded-xl border border-white/[0.08] bg-white/[0.03] px-3 py-2 text-xs text-white/50">
                <span className="h-1.5 w-1.5 rounded-full bg-emerald-400" />
                Live Support
              </div>
              <a href="#contact" className="hidden sm:inline-flex items-center rounded-xl px-4 py-2 text-sm font-semibold text-white bg-gradient-to-r from-[#3B82F6] to-[#6366F1] hover:opacity-90 transition shadow-lg shadow-blue-500/20">
                Start Project
              </a>
              <button className="md:hidden p-2 rounded-lg hover:bg-white/[0.06] text-white/70" onClick={() => setMenuOpen(!menuOpen)}>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  {menuOpen
                    ? <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    : <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />}
                </svg>
              </button>
            </div>
          </div>

          {menuOpen && (
            <motion.nav initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }} className="md:hidden py-4 flex flex-col gap-2 border-t border-white/[0.06] mt-1">
              {navItems.map((item) => (
