                  type={field.type}
                  name={field.name}
                  placeholder={field.placeholder}
                  className="rounded-xl border border-white/[0.08] bg-white/[0.03] text-white px-4 py-3 text-sm outline-none placeholder-white/25 focus:border-blue-500/50 focus:ring-1 focus:ring-blue-500/30 transition"
                />
              </div>
            ))}

            <div className="grid gap-1.5">
              <label className="text-sm font-medium text-white/60">Project Type</label>
              <select name="service" className="rounded-xl border border-white/[0.08] bg-[#060A12] text-white px-4 py-3 text-sm outline-none focus:border-blue-500/50 focus:ring-1 focus:ring-blue-500/30 transition">
                <optgroup label="Construction & Exterior">
                  <option>Custom Deck Building</option>
                  <option>Premium Fence Installation</option>
                  <option>Outdoor Kitchen & Living</option>
                  <option>Pergola & Gazebo</option>
                  <option>Full Home Renovation</option>
                </optgroup>
                <optgroup label="Landscaping & Design">
                  <option>Luxury Landscape Design</option>
                  <option>Stone Patios & Walkways</option>
                  <option>Outdoor Lighting</option>
                  <option>Water Features</option>
                  <option>Seasonal Maintenance</option>
                </optgroup>
                <optgroup label="Property Management">
                  <option>Full Property Management</option>
                  <option>Tenant Placement</option>
                  <option>Maintenance Services</option>
                  <option>Emergency Repairs</option>
                </optgroup>
                <optgroup label="Interior Services">
                  <option>Deep Cleaning Service</option>
                  <option>Move In/Out Cleaning</option>
                  <option>Interior Renovations</option>
                  <option>Custom Carpentry</option>
                </optgroup>
                <option>Custom Project (Describe Below)</option>
              </select>
            </div>

            <div className="md:col-span-2 grid gap-1.5">
              <label className="text-sm font-medium text-white/60">Project Details</label>
              <textarea
                rows={4}
                name="message"
                placeholder="Tell us about your vision... (e.g., '500sqft composite deck with built-in seating and outdoor kitchen')"
                className="rounded-xl border border-white/[0.08] bg-white/[0.03] text-white px-4 py-3 text-sm outline-none placeholder-white/25 focus:border-blue-500/50 focus:ring-1 focus:ring-blue-500/30 transition"
              />
            </div>

            {/* Upload section */}
            <div className="md:col-span-2 rounded-2xl border border-white/[0.07] bg-white/[0.02] p-6">
              <div className="flex items-center gap-3 mb-4">
                <div className="h-9 w-9 rounded-xl bg-blue-500/15 border border-blue-500/20 grid place-items-center text-blue-400">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                  </svg>
                </div>
                <div>
                  <h3 className="text-sm font-semibold text-white">Upload photos for a faster quote</h3>
                  <p className="text-xs text-white/40">Photos = 24hr response · Video tour = 12hr response</p>
                </div>
                <span className="ml-auto text-[11px] font-semibold px-2.5 py-1 rounded-full bg-blue-500/15 text-blue-400 border border-blue-500/20">PRO TIP</span>
              </div>

              <div className="border border-dashed border-white/[0.1] rounded-xl p-8 text-center hover:border-blue-500/30 hover:bg-blue-500/[0.02] transition cursor-pointer">
                <input type="file" id="media-upload" name="media" multiple accept="image/*,video/*,.pdf,.doc,.docx" className="hidden" onChange={handleFileChange} />
                <label htmlFor="media-upload" className="cursor-pointer block">
                  <div className="w-12 h-12 bg-blue-500/15 border border-blue-500/20 rounded-xl grid place-items-center mx-auto mb-3 text-blue-400 hover:scale-110 transition">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                    </svg>
                  </div>
                  <p className="text-sm font-medium text-white/70 mb-1">Click to upload photos or videos</p>
                  <p className="text-xs text-white/30">Drag & drop · images, video, PDF, DOC</p>

                  {uploadedFiles.length > 0 && (
                    <div className="mt-4 p-3 bg-emerald-500/10 rounded-lg border border-emerald-500/20">
                      <p className="text-xs font-medium text-emerald-400 mb-2">✓ {uploadedFiles.length} file(s) ready:</p>
                      <div className="flex flex-wrap gap-2 justify-center">
                        {uploadedFiles.map((file, index) => (
                          <span key={index} className="bg-white/[0.04] px-3 py-1 rounded-full text-xs text-white/60 border border-white/[0.08]">
                            {file.name.length > 20 ? file.name.substring(0, 20) + "…" : file.name}
                          </span>
                        ))}
                      </div>
                    </div>
                  )}
                </label>
              </div>
            </div>

            <div className="md:col-span-2 flex justify-between items-center">
              <p className="text-xs text-white/30 flex items-center gap-2">
                <svg className="w-4 h-4 text-white/30" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                </svg>
                Your files are secure and confidential
              </p>
              <button
                type="submit"
                className="inline-flex items-center gap-2 rounded-xl px-8 py-3.5 text-sm font-semibold text-white bg-gradient-to-r from-[#3B82F6] to-[#6366F1] shadow-lg shadow-blue-500/25 hover:opacity-90 hover:scale-[1.02] transition-all"
              >
                Get My Quote
                <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8l4 4m0 0l-4 4m4-4H3" />
                </svg>
              </button>
            </div>
          </form>
        </div>
      </section>

      {/* ─── FOOTER ─── */}
      <footer className="border-t border-white/[0.06] py-10 relative z-10">
        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <div className="h-8 w-8 rounded-lg bg-gradient-to-br from-[#3B82F6] to-[#8B5CF6] grid place-items-center">
                <span className="text-white font-black text-sm">M</span>
              </div>
              <span className="font-bold text-white">MapleLuxe</span>
            </div>
            <p className="text-sm text-white/30">Premium contracting and property management across Calgary.</p>
            <p className="text-xs text-white/20">© 2025 MapleLuxe. Licensed & Insured.</p>
          </div>
        </div>
      </footer>

      {/* Marquee keyframe */}
      <style>{`
        @keyframes marquee {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }
      `}</style>
    </div>
  );
}

